import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [isClicked, setIsClicked] = useState(false);

  const handleClick = () => {
    setIsClicked(true);
    setTimeout(() => setIsClicked(false), 1000); // Dura 1 segundo grande
  };

  return (
    <motion.section
      onClick={handleClick}
      whileHover={{
        backgroundColor: "#51AC95", // Verde bonito
        color: "#000000",
      }}
      animate={{
        scale: isClicked ? 1.08 : 1,
      }}
      transition={{ duration: 0.3 }}
      style={{
        backgroundColor: "white",
        padding: "3rem 2rem",
        margin: "2rem auto",
        borderRadius: "1rem",
        boxShadow: "0 0 20px rgba(0,0,0,0.1)",
        cursor: "pointer",
        ...style,
      }}
    >
      {children}
    </motion.section>
  );
};

export default AnimatedSection;
